      90: static int eightsvx_decode_frame(AVCodecContext *avctx, AVFrame *frame,
      91:                                  int *got_frame_ptr, AVPacket *avpkt)
      92: {
      93:     EightSvxContext *esc = avctx->priv_data;
      94:     int channels         = avctx->ch_layout.nb_channels;
      95:     int buf_size;
      96:     int ch, ret;
      97:     int hdr_size = 2;
      98: 
      99:     /* decode and interleave the first packet */
     100:     if (!esc->data[0] && avpkt) {
     101:         int chan_size = avpkt->size / channels - hdr_size;
     102: 
     103:         if (avpkt->size % channels) {
     104:             av_log(avctx, AV_LOG_WARNING, "Packet with odd size, ignoring last byte\n");
     105:         }
     106:         if (avpkt->size < (hdr_size + 1) * channels) {
     107:             av_log(avctx, AV_LOG_ERROR, "packet size is too small\n");
     108:             return AVERROR_INVALIDDATA;
     109:         }
     110: 
     111:         esc->fib_acc[0] = avpkt->data[1] + 128;
     112:         if (channels == 2)
     113:             esc->fib_acc[1] = avpkt->data[2+chan_size+1] + 128;
     114: 
     115:         esc->data_idx  = 0;
     116:         esc->data_size = chan_size;
>>   117:         if (!(esc->data[0] = av_malloc(chan_size)))
     118:             return AVERROR(ENOMEM);
     119:         if (channels == 2) {
     120:             if (!(esc->data[1] = av_malloc(chan_size))) {
     121:                 av_freep(&esc->data[0]);
     122:                 return AVERROR(ENOMEM);
     123:             }
     124:         }
     125:         memcpy(esc->data[0], &avpkt->data[hdr_size], chan_size);
     126:         if (channels == 2)
     127:             memcpy(esc->data[1], &avpkt->data[2*hdr_size+chan_size], chan_size);
     128:     }
     129:     if (!esc->data[0]) {
     130:         av_log(avctx, AV_LOG_ERROR, "unexpected empty packet\n");
     131:         return AVERROR_INVALIDDATA;
     132:     }
     133: 
     134:     /* decode next piece of data from the buffer */
     135:     buf_size = FFMIN(MAX_FRAME_SIZE, esc->data_size - esc->data_idx);
     136:     if (buf_size <= 0) {
     137:         *got_frame_ptr = 0;
     138:         return avpkt->size;
     139:     }
     140: 
     141:     /* get output buffer */
     142:     frame->nb_samples = buf_size * 2;
     143:     if ((ret = ff_get_buffer(avctx, frame, 0)) < 0)
     144:         return ret;
     145: 
     146:     for (ch = 0; ch < channels; ch++) {
     147:         delta_decode(frame->data[ch], &esc->data[ch][esc->data_idx],
     148:                      buf_size, &esc->fib_acc[ch], esc->table);
     149:     }
     150: 
     151:     esc->data_idx += buf_size;
     152: 
     153:     *got_frame_ptr = 1;
     154: 
     155:     return ((avctx->frame_num == 0) * hdr_size + buf_size) * channels;
     156: }

