     127:             memcpy(esc->data[1], &avpkt->data[2*hdr_size+chan_size], chan_size);
     128:     }
     129:     if (!esc->data[0]) {
     130:         av_log(avctx, AV_LOG_ERROR, "unexpected empty packet\n");
     131:         return AVERROR_INVALIDDATA;
     132:     }
     133: 
     134:     /* decode next piece of data from the buffer */
     135:     buf_size = FFMIN(MAX_FRAME_SIZE, esc->data_size - esc->data_idx);
     136:     if (buf_size <= 0) {
     137:         *got_frame_ptr = 0;
     138:         return avpkt->size;
     139:     }
     140: 
     141:     /* get output buffer */
     142:     frame->nb_samples = buf_size * 2;
     143:     if ((ret = ff_get_buffer(avctx, frame, 0)) < 0)
     144:         return ret;
     145: 
     146:     for (ch = 0; ch < channels; ch++) {
     147:         delta_decode(frame->data[ch], &esc->data[ch][esc->data_idx],
     148:                      buf_size, &esc->fib_acc[ch], esc->table);
     149:     }
     150: 
     151:     esc->data_idx += buf_size;
     152: 
     153:     *got_frame_ptr = 1;
     154: 
     155:     return ((avctx->frame_num == 0) * hdr_size + buf_size) * channels;
     156: }

