    2425:         !FF_ALLOCZ_TYPED_ARRAY(s->mdct_coef_buffer,  total_coefs)          ||
    2426:         !FF_ALLOC_TYPED_ARRAY(s->exp_buffer,         total_coefs)          ||
    2427:         !FF_ALLOC_TYPED_ARRAY(s->grouped_exp_buffer, channel_blocks * 128) ||
